import './DropdownSectionHeader.scss';

import { Typography } from ':components/Typography';
import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import type { DropdownSectionHeaderProps } from '../Dropdown.types';

export const DropdownSectionHeader: FC<DropdownSectionHeaderProps> = ({
	label,
	withTopBorder = false,
	className,
	dataTestId = 'DropdownSectionHeader',
	...props
}) => (
	<div
		className={classNames(
			'dsb_dropdown-section-header',
			{ 'dsb_dropdown-section-header--with-top-border': withTopBorder },
			className,
		)}
		data-testid={dataTestId}
		{...props}
	>
		{typeof label === 'string' ? <Typography variant="overline">{label}</Typography> : label}
	</div>
);
